// 센서 데이터 읽기 (시뮬레이션)
// 실배포 시 Modbus/GPIO로 교체

function randomInRange(min, max) {
    return Math.round((Math.random() * (max - min) + min) * 100) / 100;
}

var sensorData = {
    temp_001: randomInRange(-10, 50),
    humidity_001: randomInRange(0, 100)
};

// 센서 데이터를 글로벌 컨텍스트에 저장
global.set('latest_sensor_data', sensorData);

// API 전송용 payload 구성
msg.payload = {
    farmId: 'farm_0001',
    houseId: 'house_001',
    data: sensorData
};

msg.headers = {
    'Content-Type': 'application/json',
    'x-api-key': 'smartfarm-sensor-key'
};

return msg;

function randomInRange(min, max) {
    return Math.round((Math.random() * (max - min) + min) * 100) / 100;
}

var sensorData = {
    temp_001: randomInRange(-10, 50),
    humidity_001: randomInRange(0, 100)
};

global.set('latest_sensor_data', sensorData);

msg.payload = {
    farmId: 'farm_0001',
    houseId: 'house_001',
    data: sensorData
};

msg.headers = {
    'Content-Type': 'application/json',
    'x-api-key': 'smartfarm-sensor-key'
};

return msg;

var interval = flow.get('intervalSeconds') || 60;

if (msg.statusCode === 201) {
    node.status({fill:'green', shape:'dot', text:'전송 성공 (다음: ' + interval + '초 후)'});
} else {
    node.status({fill:'red', shape:'ring', text:'전송 실패: ' + (msg.statusCode || 'timeout')});
}

return null;

var interval = flow.get('intervalSeconds') || 60;
msg.delay = interval * 1000;
return msg;

msg.headers = {
    'x-api-key': 'smartfarm-sensor-key'
};
return msg;

if (msg.statusCode !== 200 || !msg.payload.success) {
    node.status({fill:'red', shape:'ring', text:'서버 응답 오류'});
    return null;
}

var data = msg.payload.data;
var interval = data.intervalSeconds || 60;

flow.set('intervalSeconds', interval);
flow.set('sensors', data.sensors);

node.status({fill:'green', shape:'dot', text:'수집간격: ' + interval + '초'});

return msg;

// 장비 상태를 Flow Context에서 읽기
// 관수 시퀀스 및 수동 제어에서 상태가 업데이트됨

var VALVE_COUNT = 14;

// 기본값 설정
var defaultValveStates = [];
for (var i = 0; i < VALVE_COUNT; i++) {
    defaultValveStates.push(false);
}

var operatingState = flow.get('operating_state') || 'STOPPED';
var activeProgram = flow.get('active_program') || null;
var valveStates = flow.get('valve_states') || defaultValveStates;
var pumpState = flow.get('pump_state') || { raw_pump: false, nutrient_pump: false };
var mixerState = flow.get('mixer_state') || false;

msg.payload = {
    operating_state: operatingState,
    active_program: activeProgram,
    valve_states: valveStates,
    pump_state: pumpState,
    mixer_state: mixerState
};

msg.headers = { 'Content-Type': 'application/json' };

return msg;

// 관수 프로그램 트리거 조건 확인
// 3가지 트리거: 일사량, 시간간격, 고정시간

var response = msg.payload;
var programs = (response && response.data) ? response.data : response;
if (!programs || !Array.isArray(programs)) {
    node.warn('프로그램 목록을 가져올 수 없습니다: ' + JSON.stringify(msg.payload));
    return [null, msg];
}

var now = new Date();
var currentDay = now.getDay(); // 0=일, 1=월, ..., 6=토
var currentHour = now.getHours();
var currentMinute = now.getMinutes();
var currentTimeStr = ('0' + currentHour).slice(-2) + ':' + ('0' + currentMinute).slice(-2);

// 현재 운영 상태 확인
var operatingState = flow.get('operating_state') || 'STOPPED';
if (operatingState === 'EMERGENCY' || operatingState === 'IRRIGATING') {
    // 비상정지 상태이거나 이미 관수 중이면 트리거하지 않음
    return [null, { payload: '현재 상태: ' + operatingState + ' - 트리거 건너뜀' }];
}

var sensorData = global.get('latest_sensor_data') || {};
var accumulatedSolar = flow.get('accumulated_solar') || 0;

// 누적 일사량 계산 (10초 간격이므로 일사량 * 10/3600 적산)
if (sensorData.solar_radiation) {
    accumulatedSolar += sensorData.solar_radiation * (10 / 3600);
    flow.set('accumulated_solar', accumulatedSolar);
}

var triggeredProgram = null;

for (var i = 0; i < programs.length; i++) {
    var program = programs[i];

    // 프로그램 활성화 여부 확인
    if (!program.enabled) continue;

    // 요일 확인
    if (program.active_days && Array.isArray(program.active_days)) {
        if (!program.active_days[currentDay]) continue;
    }

    var triggerType = program.trigger_type;
    var lastIrrigationTime = flow.get('last_irrigation_' + program.program_id) || 0;

    if (triggerType === 'solar') {
        // 일사량 기반 트리거
        if (program.trigger_solar_radiation && accumulatedSolar >= program.trigger_solar_radiation) {
            triggeredProgram = program;
            // 누적 일사량 리셋
            flow.set('accumulated_solar', 0);
            node.status({ fill: 'green', shape: 'dot', text: '일사량 트리거: ' + program.name });
            break;
        }
    } else if (triggerType === 'interval') {
        // 시간 간격 기반 트리거
        var elapsedMinutes = (now.getTime() - lastIrrigationTime) / 60000;
        if (program.trigger_interval_minutes && elapsedMinutes >= program.trigger_interval_minutes) {
            triggeredProgram = program;
            node.status({ fill: 'green', shape: 'dot', text: '시간간격 트리거: ' + program.name });
            break;
        }
    } else if (triggerType === 'schedule') {
        // 고정 시간 기반 트리거
        if (program.trigger_start_time === currentTimeStr) {
            // 같은 시간에 중복 트리거 방지
            var lastScheduleTrigger = flow.get('last_schedule_trigger_' + program.program_id) || '';
            var todayKey = now.toISOString().slice(0, 10) + '_' + currentTimeStr;
            if (lastScheduleTrigger !== todayKey) {
                flow.set('last_schedule_trigger_' + program.program_id, todayKey);
                triggeredProgram = program;
                node.status({ fill: 'green', shape: 'dot', text: '고정시간 트리거: ' + program.name });
                break;
            }
        }
    }
}

if (triggeredProgram) {
    // 마지막 관수 시간 기록
    flow.set('last_irrigation_' + triggeredProgram.program_id, now.getTime());

    var triggerMsg = {
        payload: triggeredProgram,
        topic: 'irrigation_trigger'
    };
    return [triggerMsg, null];
} else {
    node.status({ fill: 'grey', shape: 'ring', text: '대기 중 - ' + currentTimeStr });
    return [null, { payload: '트리거 조건 미충족' }];
}

// 5단계 관수 시퀀스 상태 머신
// STEP 1: 원수 펌프 ON → 3초 대기
// STEP 2: 양액 혼합 → 믹서 ON → EC/pH 목표 도달 대기 (최대 60초)
// STEP 3: 양액 펌프 ON
// STEP 4: 밸브 순차 개방
// STEP 5: 완료 → 전체 OFF → 실행 기록

var VALVE_COUNT = 14;
var program = msg.payload;
var currentStep = flow.get('irrigation_step') || 0;
var stepStartTime = flow.get('step_start_time') || 0;
var currentValveIdx = flow.get('current_valve_index') || 0;
var now = Date.now();

// 새 프로그램 트리거 시 초기화
if (msg.topic === 'irrigation_trigger' && currentStep === 0) {
    flow.set('irrigation_program', program);
    flow.set('irrigation_step', 1);
    flow.set('step_start_time', now);
    flow.set('current_valve_index', 0);
    flow.set('operating_state', 'IRRIGATING');
    flow.set('active_program', program.program_id || program.name);
    flow.set('irrigation_total_flow', 0);

    // STEP 1: 원수 펌프 ON
    var pumpState = { raw_pump: true, nutrient_pump: false };
    flow.set('pump_state', pumpState);

    node.status({ fill: 'blue', shape: 'dot', text: 'STEP 1: 원수 펌프 ON' });

    msg.payload = {
        operating_state: 'IRRIGATING',
        active_program: program.program_id || program.name,
        valve_states: flow.get('valve_states') || new Array(VALVE_COUNT).fill(false),
        pump_state: pumpState,
        mixer_state: false
    };
    msg.headers = { 'Content-Type': 'application/json' };
    msg.delay = 3000; // 3초 대기
    msg.nextStep = 2;
    return msg;
}

program = flow.get('irrigation_program');
if (!program) {
    node.status({ fill: 'grey', shape: 'ring', text: '프로그램 없음' });
    return null;
}

currentStep = flow.get('irrigation_step');

if (currentStep === 2) {
    // STEP 2: 양액 혼합 - 믹서 ON
    flow.set('mixer_state', true);
    flow.set('step_start_time', now);
    flow.set('irrigation_step', 2);

    var sensorData = global.get('latest_sensor_data') || {};
    var targetEc = program.target_ec || 2.0;
    var targetPh = program.target_ph || 6.0;
    var elapsed = (now - flow.get('step_start_time')) / 1000;

    // EC/pH 목표 도달 확인 (시뮬레이션에서는 즉시 통과, 실배포 시 센서 값 비교)
    // 최대 60초 타임아웃
    node.status({ fill: 'blue', shape: 'dot', text: 'STEP 2: 양액 혼합 중 (목표 EC: ' + targetEc + ', pH: ' + targetPh + ')' });

    // 시뮬레이션: 즉시 다음 단계로 진행
    flow.set('irrigation_step', 3);
    msg.delay = 1000;
    msg.nextStep = 3;

    msg.payload = {
        operating_state: 'IRRIGATING',
        active_program: flow.get('active_program'),
        valve_states: flow.get('valve_states') || new Array(VALVE_COUNT).fill(false),
        pump_state: flow.get('pump_state'),
        mixer_state: true
    };
    msg.headers = { 'Content-Type': 'application/json' };
    return msg;
}

if (currentStep === 3) {
    // STEP 3: 양액 펌프 ON
    var pumpState3 = { raw_pump: true, nutrient_pump: true };
    flow.set('pump_state', pumpState3);
    flow.set('irrigation_step', 4);
    flow.set('current_valve_index', 0);
    flow.set('step_start_time', now);

    node.status({ fill: 'blue', shape: 'dot', text: 'STEP 3: 양액 펌프 ON' });

    msg.payload = {
        operating_state: 'IRRIGATING',
        active_program: flow.get('active_program'),
        valve_states: flow.get('valve_states') || new Array(VALVE_COUNT).fill(false),
        pump_state: pumpState3,
        mixer_state: true
    };
    msg.headers = { 'Content-Type': 'application/json' };
    msg.delay = 1000;
    msg.nextStep = 4;
    return msg;
}

if (currentStep === 4) {
    // STEP 4: 밸브 순차 개방
    var valveConfigs = program.valve_configs || program.valves || [];
    currentValveIdx = flow.get('current_valve_index') || 0;

    if (currentValveIdx >= valveConfigs.length) {
        // 모든 밸브 완료 → STEP 5로
        flow.set('irrigation_step', 5);
        msg.delay = 500;
        msg.nextStep = 5;
        msg.payload = {
            operating_state: 'IRRIGATING',
            active_program: flow.get('active_program'),
            valve_states: new Array(VALVE_COUNT).fill(false),
            pump_state: flow.get('pump_state'),
            mixer_state: flow.get('mixer_state')
        };
        msg.headers = { 'Content-Type': 'application/json' };
        node.status({ fill: 'blue', shape: 'dot', text: 'STEP 4: 모든 밸브 완료' });
        return msg;
    }

    var currentValve = valveConfigs[currentValveIdx];
    var valveIndex = currentValve.valve_index || currentValveIdx;
    var duration = (currentValve.duration_seconds || 60) * 1000; // ms로 변환

    // 현재 밸브 열기
    var valveStates = new Array(VALVE_COUNT).fill(false);
    valveStates[valveIndex] = true;
    flow.set('valve_states', valveStates);

    // 유량 누적
    var sensorNow = global.get('latest_sensor_data') || {};
    var totalFlow = flow.get('irrigation_total_flow') || 0;
    totalFlow += sensorNow.supply_flow || 0;
    flow.set('irrigation_total_flow', totalFlow);

    // 다음 밸브로
    flow.set('current_valve_index', currentValveIdx + 1);
    flow.set('step_start_time', now);

    node.status({ fill: 'green', shape: 'dot', text: 'STEP 4: 밸브 ' + (valveIndex + 1) + ' 개방 중 (' + (currentValveIdx + 1) + '/' + valveConfigs.length + ')' });

    msg.payload = {
        operating_state: 'IRRIGATING',
        active_program: flow.get('active_program'),
        valve_states: valveStates,
        pump_state: flow.get('pump_state'),
        mixer_state: flow.get('mixer_state')
    };
    msg.headers = { 'Content-Type': 'application/json' };
    msg.delay = duration;
    msg.nextStep = 4; // 같은 STEP에서 다음 밸브
    return msg;
}

if (currentStep === 5) {
    // STEP 5: 완료 - 모든 장비 OFF
    flow.set('valve_states', new Array(VALVE_COUNT).fill(false));
    flow.set('pump_state', { raw_pump: false, nutrient_pump: false });
    flow.set('mixer_state', false);
    flow.set('operating_state', 'STOPPED');
    flow.set('active_program', null);
    flow.set('irrigation_step', 0);
    flow.set('current_valve_index', 0);

    var executionRecord = {
        program_id: program.program_id,
        program_name: program.name,
        completed_at: new Date().toISOString(),
        total_flow: flow.get('irrigation_total_flow') || 0
    };

    // 일일 실행 기록 저장
    var dailyRecords = flow.get('daily_irrigation_records') || [];
    dailyRecords.push(executionRecord);
    flow.set('daily_irrigation_records', dailyRecords);
    flow.set('irrigation_total_flow', 0);

    node.status({ fill: 'green', shape: 'ring', text: 'STEP 5: 관수 완료 - ' + (program.name || program.program_id) });

    msg.payload = {
        operating_state: 'STOPPED',
        active_program: null,
        valve_states: new Array(VALVE_COUNT).fill(false),
        pump_state: { raw_pump: false, nutrient_pump: false },
        mixer_state: false
    };
    msg.headers = { 'Content-Type': 'application/json' };
    return msg;
}

return null;

initialize:
// 초기화 시 관수 상태 리셋
flow.set('irrigation_step', 0);
flow.set('current_valve_index', 0);
flow.set('irrigation_total_flow', 0);

func:
// 다음 단계로 진행
var nextStep = msg.nextStep;
if (nextStep) {
    flow.set('irrigation_step', nextStep);
    msg.topic = 'next_step';
    msg.payload = flow.get('irrigation_program');
    return msg;
}
return null;

// 센서 임계값 확인
// 글로벌 컨텍스트에서 최신 센서 데이터 읽기

var response = msg.payload;
var config = (response && response.data) ? response.data : response;
if (!config) {
    node.warn('설정 정보를 가져올 수 없습니다.');
    return null;
}

var sensorData = global.get('latest_sensor_data');
if (!sensorData) {
    node.status({ fill: 'grey', shape: 'ring', text: '센서 데이터 없음' });
    return null;
}

// 임계값 기본값 설정
var thresholds = {
    alarm_ec_upper: config.alarm_ec_upper || 3.5,
    alarm_ec_lower: config.alarm_ec_lower || 0.3,
    alarm_ph_upper: config.alarm_ph_upper || 8.5,
    alarm_ph_lower: config.alarm_ph_lower || 4.5,
    alarm_temp_upper: config.alarm_temp_upper || 40,
    alarm_temp_lower: config.alarm_temp_lower || 5
};

// 현재 경보 상태 (중복 방지)
var activeAlarms = flow.get('active_alarms') || {};
var alarms = [];

// EC 상한 확인
if (sensorData.ec > thresholds.alarm_ec_upper) {
    if (!activeAlarms['EC_HIGH']) {
        alarms.push({
            alarm_type: 'EC_HIGH',
            alarm_value: sensorData.ec,
            threshold_value: thresholds.alarm_ec_upper,
            message: 'EC 상한 초과: 현재 ' + sensorData.ec + ' (임계값: ' + thresholds.alarm_ec_upper + ')'
        });
        activeAlarms['EC_HIGH'] = true;
    }
} else {
    activeAlarms['EC_HIGH'] = false;
}

// EC 하한 확인
if (sensorData.ec < thresholds.alarm_ec_lower) {
    if (!activeAlarms['EC_LOW']) {
        alarms.push({
            alarm_type: 'EC_LOW',
            alarm_value: sensorData.ec,
            threshold_value: thresholds.alarm_ec_lower,
            message: 'EC 하한 미달: 현재 ' + sensorData.ec + ' (임계값: ' + thresholds.alarm_ec_lower + ')'
        });
        activeAlarms['EC_LOW'] = true;
    }
} else {
    activeAlarms['EC_LOW'] = false;
}

// pH 상한 확인
if (sensorData.ph > thresholds.alarm_ph_upper) {
    if (!activeAlarms['PH_HIGH']) {
        alarms.push({
            alarm_type: 'PH_HIGH',
            alarm_value: sensorData.ph,
            threshold_value: thresholds.alarm_ph_upper,
            message: 'pH 상한 초과: 현재 ' + sensorData.ph + ' (임계값: ' + thresholds.alarm_ph_upper + ')'
        });
        activeAlarms['PH_HIGH'] = true;
    }
} else {
    activeAlarms['PH_HIGH'] = false;
}

// pH 하한 확인
if (sensorData.ph < thresholds.alarm_ph_lower) {
    if (!activeAlarms['PH_LOW']) {
        alarms.push({
            alarm_type: 'PH_LOW',
            alarm_value: sensorData.ph,
            threshold_value: thresholds.alarm_ph_lower,
            message: 'pH 하한 미달: 현재 ' + sensorData.ph + ' (임계값: ' + thresholds.alarm_ph_lower + ')'
        });
        activeAlarms['PH_LOW'] = true;
    }
} else {
    activeAlarms['PH_LOW'] = false;
}

// 온도 상한 확인
if (sensorData.indoor_temp > thresholds.alarm_temp_upper) {
    if (!activeAlarms['TEMP_HIGH']) {
        alarms.push({
            alarm_type: 'TEMP_HIGH',
            alarm_value: sensorData.indoor_temp,
            threshold_value: thresholds.alarm_temp_upper,
            message: '온도 상한 초과: 현재 ' + sensorData.indoor_temp + '°C (임계값: ' + thresholds.alarm_temp_upper + '°C)'
        });
        activeAlarms['TEMP_HIGH'] = true;
    }
} else {
    activeAlarms['TEMP_HIGH'] = false;
}

// 온도 하한 확인
if (sensorData.indoor_temp < thresholds.alarm_temp_lower) {
    if (!activeAlarms['TEMP_LOW']) {
        alarms.push({
            alarm_type: 'TEMP_LOW',
            alarm_value: sensorData.indoor_temp,
            threshold_value: thresholds.alarm_temp_lower,
            message: '온도 하한 미달: 현재 ' + sensorData.indoor_temp + '°C (임계값: ' + thresholds.alarm_temp_lower + '°C)'
        });
        activeAlarms['TEMP_LOW'] = true;
    }
} else {
    activeAlarms['TEMP_LOW'] = false;
}

flow.set('active_alarms', activeAlarms);

if (alarms.length > 0) {
    node.status({ fill: 'red', shape: 'dot', text: '경보 ' + alarms.length + '건 발생' });
    // 각 경보를 개별 메시지로 전송
    var messages = alarms.map(function(alarm) {
        return {
            payload: alarm,
            headers: { 'Content-Type': 'application/json' }
        };
    });
    // 첫 번째 경보만 전송 (순차 처리)
    msg.payload = alarms[0];
    msg.headers = { 'Content-Type': 'application/json' };
    msg.alarms = alarms;
    return msg;
} else {
    node.status({ fill: 'green', shape: 'ring', text: '정상 범위 내' });
    return null;
}

// 비상정지 실행
// 모든 밸브 OFF, 모든 펌프 OFF, 믹서 OFF

var VALVE_COUNT = 14;

// 모든 장비 OFF
var valveStates = new Array(VALVE_COUNT).fill(false);
var pumpState = { raw_pump: false, nutrient_pump: false };
var mixerState = false;

// Flow Context 업데이트
flow.set('valve_states', valveStates);
flow.set('pump_state', pumpState);
flow.set('mixer_state', mixerState);
flow.set('operating_state', 'EMERGENCY');
flow.set('active_program', null);

// 진행 중인 관수 시퀀스 초기화
flow.set('irrigation_step', 0);
flow.set('current_valve_index', 0);
flow.set('irrigation_total_flow', 0);

node.status({ fill: 'red', shape: 'dot', text: '비상정지 실행됨' });
node.warn('비상정지가 실행되었습니다. 모든 장비가 OFF 되었습니다.');

// Express에 상태 업데이트 전송용 메시지
var statusMsg = {
    payload: {
        operating_state: 'EMERGENCY',
        active_program: null,
        valve_states: valveStates,
        pump_state: pumpState,
        mixer_state: mixerState
    },
    headers: { 'Content-Type': 'application/json' }
};

// HTTP 응답용 메시지
var responseMsg = {
    payload: {
