                node.warn(`🔓 ${deviceId} 열기: GPIO ${pins.open} HIGH`);
            } else if (command === 'close') {
                // GPIO pins.close HIGH, pins.open LOW
                node.warn(`🔒 ${deviceId} 닫기: GPIO ${pins.close} HIGH`);
