if (rules.length === 0) {
    node.status({ fill: 'grey', shape: 'dot', text: '활성 규칙 없음' });
    return null;
}

const now = new Date();
const actionsToExecute = [];
const updateMessages = [];

for (const rule of rules) {
    // 조건/액션 JSON 파싱
    var conditions, actions;
    try { conditions = JSON.parse(rule.conditions); } catch(e) { continue; }
    try { actions = JSON.parse(rule.actions); } catch(e) { continue; }

    // 쿨다운 체크
    if (rule.last_triggered_at) {
        var elapsed = (now.getTime() - new Date(rule.last_triggered_at).getTime()) / 1000;
        if (elapsed < rule.cooldown_seconds) {
            continue;
        }
    }

    // 조건 평가
    var conditionResults = conditions.map(function(cond) {
        if (cond.type === 'sensor') {
            var sensorValue = sensorData.data[cond.sensorId];
            if (sensorValue === undefined || sensorValue === null) return false;
            switch (cond.operator) {
                case '>': return sensorValue > cond.value;
                case '>=': return sensorValue >= cond.value;
                case '<': return sensorValue < cond.value;
                case '<=': return sensorValue <= cond.value;
                case '==': return Math.abs(sensorValue - cond.value) < 0.1;
                default: return false;
            }
        }
        if (cond.type === 'time') {
            var currentDay = now.getDay();
            if (cond.days && cond.days.length > 0 && cond.days.indexOf(currentDay) === -1) {
                return false;
            }
            if (cond.time) {
                var parts = cond.time.split(':');
                var hour = parseInt(parts[0]);
                var minute = parseInt(parts[1]);
                var nowMinutes = now.getHours() * 60 + now.getMinutes();
                var targetMinutes = hour * 60 + minute;
                return Math.abs(nowMinutes - targetMinutes) <= 2;
            }
            return false;
        }
        return false;
    });

    // AND/OR 로직
    var triggered = false;
    if (rule.condition_logic === 'AND') {
        triggered = conditionResults.length > 0 && conditionResults.every(function(r) { return r === true; });
    } else {
        triggered = conditionResults.some(function(r) { return r === true; });
    }

    if (triggered) {
        // 이유 텍스트 생성
        var reasonParts = conditions.map(function(cond) {
            if (cond.type === 'sensor') {
                var val = sensorData.data[cond.sensorId];
                return (cond.sensorName || cond.sensorId) + ' ' + val + cond.operator + cond.value;
            }
            if (cond.type === 'time') return '시간 ' + cond.time;
            return '';
        }).filter(function(s) { return s; });
        var reason = rule.name + ': ' + reasonParts.join(rule.condition_logic === 'AND' ? ' AND ' : ' OR ');

        for (var i = 0; i < actions.length; i++) {
            var action = actions[i];
            actionsToExecute.push({
                ruleId: rule.id,
                ruleName: rule.name,
                houseId: rule.house_id,
                deviceId: action.deviceId,
                deviceType: action.deviceType,
                deviceName: action.deviceName || action.deviceId,
                command: action.command,
                reason: reason
            });
        }

        // last_triggered_at, trigger_count 업데이트 SQL
        var newCount = (rule.trigger_count || 0) + 1;
        updateMessages.push({
            topic: 'UPDATE automation_rules SET last_triggered_at = $1, trigger_count = $2, synced = 0 WHERE id = $3',
            payload: [now.toISOString(), newCount, rule.id]
        });

        node.warn('🤖 자동화 실행: ' + rule.name + ' → ' + actions.map(function(a) { return a.deviceId + ' ' + a.command; }).join(', '));
    }
}

