msg._pragmaIdx = 0;
msg.topic = pragmas[0];
node.warn('⚙️ SQLite PRAGMA 설정 시작 (5개)');
return msg;

var idx = (msg._pragmaIdx || 0) + 1;
var list = msg._pragmaList || [];
if (idx < list.length) {
  msg._pragmaIdx = idx;
  msg.topic = list[idx];
  return [msg, null];
}
node.warn('✅ PRAGMA 5개 설정 완료');
return [null, msg];

